const body = $input.first().json.body;
const event = body.event || 'unknown';
const payload = body.payload || {};

// Map external events to agent tasks
const taskMap = {
  'github.push': `New push to ${payload.repo || 'repo'}: review changes, run tests, update docs if needed.`,
  'github.issue': `New issue #${payload.number || '?'} on ${payload.repo || 'repo'}: "${payload.title || 'untitled'}". Triage and respond.`,
  'payment.received': `Payment received: $${payload.amount || '?'} from ${payload.from || 'unknown'}. Update invoice tracker.`,
  'alert.security': `Security alert: ${payload.message || 'unknown threat'}. Investigate immediately.`,
  'custom': payload.task || 'Process incoming webhook event.'
};

const task = taskMap[event] || `Process webhook event '${event}': ${JSON.stringify(payload).slice(0, 500)}`;
const priority = ['alert.security'].includes(event) ? 'high' : 'normal';
const model = priority === 'high' ? 'anthropic/claude-opus-4-6' : 'anthropic/claude-sonnet-4-20250514';

return [{ json: { event, task, model, priority, label: `webhook-${event.replace('.', '-')}` } }];
